import{_ as e,o as i,c as n,a2 as o}from"./chunks/framework.Bix3-HpO.js";const g=JSON.parse('{"title":"Plugin Setup","description":"DinOdds Plugin Setup","frontmatter":{"title":"Plugin Setup","description":"DinOdds Plugin Setup","weight":30,"extra":{"order":30},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/dinodds/plugin-setup"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/dinodds/plugin-setup"}],["meta",{"property":"og:title","content":"Plugin Setup"}],["meta",{"property":"og:description","content":"DinOdds Plugin Setup"}],["meta",{"name":"twitter:title","content":"Plugin Setup"}],["meta",{"name":"twitter:description","content":"DinOdds Plugin Setup"}]]},"headers":[],"relativePath":"docs/dinodds/plugin-setup.md","filePath":"docs/dinodds/plugin-setup.md"}'),a={name:"docs/dinodds/plugin-setup.md"};function d(r,t,s,l,u,p){return i(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="plugin-setup" tabindex="-1">Plugin Setup <a class="header-anchor" href="#plugin-setup" aria-label="Permalink to &quot;Plugin Setup&quot;">​</a></h1><p>You need to set up the plugin to be able to use it.</p><h2 id="client-id" tabindex="-1">Client ID <a class="header-anchor" href="#client-id" aria-label="Permalink to &quot;Client ID&quot;">​</a></h2><p>Your DinOdds Client ID is the license key you get when purchasing a subscription. You can get it from your <a href="https://dinomatic.com/account" target="_blank" rel="noreferrer">DinoMatic account</a>.</p><h3 id="add-client-id" tabindex="-1">Add Client ID <a class="header-anchor" href="#add-client-id" aria-label="Permalink to &quot;Add Client ID&quot;">​</a></h3><p>After activating DinOdds plugin, you&#39;ll find a new menu item in your WordPress dashboard left hand navigation: <strong>DinOdds</strong>. Visit that page by clicking the menu item or <strong>Settings</strong> link in your plugins listing.</p><p>You&#39;ll be prompted to add your Client ID, enter it and click the <strong>Save</strong> button.</p><p><img src="https://media.dinomatic.com/images/docs/dinodds/plugin-setup.jpg" alt="DinOdds Plugin Setup"></p><p>If you get an error that the license key is not correct and the registration fails:</p><ul><li>make sure there are no white spaces in the beginning or at the end of the key</li><li>if you have firewall installed on your server, make sure requests to dinomatic.com are not being blocked</li></ul>',10)])])}const h=e(a,[["render",d]]);export{g as __pageData,h as default};
